function extractName(node: any): string | null {
	// Look for a 'name' or 'identifier' child
	for (const child of node.children ?? []) {
		if (
			child.type === "identifier" ||
			child.type === "property_identifier" ||
			child.type === "type_identifier"
		) {
			return child.text;
		}
	}
	return null;
}

