function stripQuotes(str: string, includeBrackets = false): string {
	if (str.length < 2) return str;
	const first = str[0];
	const last = str[str.length - 1];
	if ((first === '"' && last === '"') || (first === "'" && last === "'") || (first === '`' && last === '`')) {
		return str.slice(1, -1);
	}
	if (includeBrackets && first === '<' && last === '>') {
		return str.slice(1, -1);
	}
	return str;
}

